package com.gateway.apigateway.security;

import io.jsonwebtoken.Claims;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.cloud.gateway.filter.GatewayFilterChain;
import org.springframework.cloud.gateway.filter.GlobalFilter;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Component;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;

import java.util.List;

@Component
public class JwtAuthenticationFilter implements GlobalFilter {

    private static final Logger log =
            LoggerFactory.getLogger(JwtAuthenticationFilter.class);

    private final JwtUtil jwtUtil;

    public JwtAuthenticationFilter(JwtUtil jwtUtil) {
        this.jwtUtil = jwtUtil;
    }

    @Override
    public Mono<Void> filter(ServerWebExchange exchange, GatewayFilterChain chain) {

        String path = exchange.getRequest().getURI().getPath();

        // 🔓 Public endpoints
        if (path.startsWith("/auth")) {
            return chain.filter(exchange);
        }

        String authHeader = exchange.getRequest()
                .getHeaders()
                .getFirst(HttpHeaders.AUTHORIZATION);

        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            return unauthorized(exchange);
        }

        try {
            String token = authHeader.substring(7);
            Claims claims = jwtUtil.parseToken(token);

            if (jwtUtil.isExpired(claims)) {
                return unauthorized(exchange);
            }

            List<String> roles = jwtUtil.getRoles(claims);
            List<String> finalRoles = (roles == null) ? List.of() : roles;

            // 🔐 ROLE CHECKS (ADMIN OVERRIDE)
            if (!isAuthorized(path, finalRoles)) {
                return forbidden(exchange);
            }

            // ✅ Forward identity to downstream services
            exchange = exchange.mutate()
                    .request(r -> r
                            .header("X-User-Id", claims.getSubject())
                            .header("X-Roles", String.join(",", finalRoles))
                    )
                    .build();

            return chain.filter(exchange);

        } catch (Exception e) {
            log.error("JWT validation failed", e);
            return unauthorized(exchange);
        }
    }

    // =========================
    // 🔐 Authorization Logic
    // =========================
    private boolean isAuthorized(String path, List<String> roles) {

        // ADMIN can access everything
        if (roles.contains("ROLE_ADMIN")) {
            return true;
        }

        // USER routes
        if (path.startsWith("/users") || path.startsWith("/contacts")) {
            return roles.contains("ROLE_USER");
        }

        // ADMIN-only routes
        if (path.startsWith("/admin")) {
            return false;
        }

        // Default allow
        return true;
    }

    private Mono<Void> unauthorized(ServerWebExchange exchange) {
        exchange.getResponse().setStatusCode(HttpStatus.UNAUTHORIZED);
        return exchange.getResponse().setComplete();
    }

    private Mono<Void> forbidden(ServerWebExchange exchange) {
        exchange.getResponse().setStatusCode(HttpStatus.FORBIDDEN);
        return exchange.getResponse().setComplete();
    }
}



