2.5 Key Resolver (Identify Users)


Create:


api-gateway/security/UserKeyResolver.java


@Component
public class UserKeyResolver implements KeyResolver {

    @Override
    public Mono<String> resolve(ServerWebExchange exchange) {

        String userId = exchange
                .getRequest()
                .getHeaders()
                .getFirst("X-User-Id");

        if(userId == null){
            userId = exchange
                    .getRequest()
                    .getRemoteAddress()
                    .getAddress()
                    .getHostAddress();
        }

        return Mono.just(userId);
    }
}



